'use client';

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { geminiApi, toApiError } from '@/services/api';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';

type StepKey = 1 | 2 | 3 | 4;

interface StepState<T> {
  data: T | null;
  isLoading: boolean;
  isApproved: boolean;
  locked: boolean;
  error: string | null;
  lastUpdated: string | null;
}

interface Step1Result {
  characterBreakdown: string[];
  analysisMarkdown: string;
  structuredJson: Record<string, unknown> | null;
}

interface Character {
  name: string;
  description: string;
  imagePrompt: string;
}

interface Step2Result {
  globalGuidelines: string;
  mainCharacters: Character[];
  supportingCharacters: Character[];
}

interface PanelScript {
  pageNumber: number;
  layoutSummary: string;
  panels: {
    panelNumber: number;
    description: string;
    dialogue: string;
    imagePrompt: string;
  }[];
}

interface Step3Result {
  totalPages: number;
  scripts: PanelScript[];
}

interface Step4Result {
  images: {
    id: string;
    pageNumber: number;
    panelNumber: number;
    prompt: string;
    imageUrl: string;
  }[];
}

type StepData = Step1Result | Step2Result | Step3Result | Step4Result;

interface ApprovedCacheEntry {
  key: string;
  data: StepData;
}

const emptyStepState = <T,>(locked: boolean): StepState<T> => ({
  data: null,
  isLoading: false,
  isApproved: false,
  locked,
  error: null,
  lastUpdated: null,
});

export default function TextToComicGenerator() {
  // Input and configuration
  const [projectId, setProjectId] = useState('three_little_pigs_manga_001');
  const [storyFile, setStoryFile] = useState<File | null>(null);
  const [storyText, setStoryText] = useState('');
  const [mainCharacters, setMainCharacters] = useState('5');
  const [numChapters, setNumChapters] = useState('4');
  const [targetPages, setTargetPages] = useState('100');
  const [mangaGenre, setMangaGenre] = useState('Fantasy/Adventure, Epic tone');
  const [artStyle, setArtStyle] = useState('Japanese manga style, detailed');
  const [maxPanelsPerPage, setMaxPanelsPerPage] = useState('6');
  const [specialRequests, setSpecialRequests] = useState('None');

  // Per-step state
  const [step1, setStep1] = useState<StepState<Step1Result>>(emptyStepState(false));
  const [step2, setStep2] = useState<StepState<Step2Result>>(emptyStepState(true));
  const [step3, setStep3] = useState<StepState<Step3Result>>(emptyStepState(true));
  const [step4, setStep4] = useState<StepState<Step4Result>>(emptyStepState(true));
  const [activeStep, setActiveStep] = useState<StepKey>(1);
  const [globalError, setGlobalError] = useState<string | null>(null);
  const [jsonCopied, setJsonCopied] = useState(false);
  const [jsonDownloaded, setJsonDownloaded] = useState(false);
  const [cooldownUntil, setCooldownUntil] = useState<Record<StepKey, number>>({
    1: 0,
    2: 0,
    3: 0,
    4: 0,
  });
  const [nowMs, setNowMs] = useState<number>(Date.now());
  const approvedCacheRef = useRef<Partial<Record<StepKey, ApprovedCacheEntry>>>({});

  useEffect(() => {
    const timer = window.setInterval(() => setNowMs(Date.now()), 1000);
    return () => window.clearInterval(timer);
  }, []);

  const stepMap: Record<StepKey, StepState<any>> = useMemo(
    () => ({ 1: step1, 2: step2, 3: step3, 4: step4 }),
    [step1, step2, step3, step4]
  );

  const setStepState = (step: StepKey, updater: (prev: StepState<any>) => StepState<any>) => {
    if (step === 1) setStep1((prev) => updater(prev));
    if (step === 2) setStep2((prev) => updater(prev));
    if (step === 3) setStep3((prev) => updater(prev));
    if (step === 4) setStep4((prev) => updater(prev));
  };

  const parseLines = (text: string, limit: number) =>
    text
      .split(/\r?\n+/)
      .map((line) => line.replace(/^[-*\d.\s]+/, '').trim())
      .filter(Boolean)
      .slice(0, limit);

  const getCompactStep1Context = (): string => {
    const structured = step1.data?.structuredJson as
      | {
          steps?: {
            step_1_analysis?: {
              data?: {
                analysis?: unknown;
                chapters_structure?: unknown;
                final_statistics?: unknown;
              };
            };
          };
        }
      | undefined;

    const step1Data = structured?.steps?.step_1_analysis?.data;
    if (!step1Data) {
      return step1.data?.analysisMarkdown || storyText;
    }

    return JSON.stringify(
      {
        analysis: step1Data.analysis,
        chapters_structure: step1Data.chapters_structure,
        final_statistics: step1Data.final_statistics,
      },
      null,
      2
    );
  };

  const buildStepPayload = async (step: StepKey): Promise<Step1Result | Step2Result | Step3Result | Step4Result> => {
    if (!storyText.trim()) {
      throw new Error('Please provide story text before generating.');
    }

    if (step === 1) {
      const resp = await geminiApi.analyzeStoryStructured({
        project_id: projectId,
        story_text: storyText,
        num_chapters: Number(numChapters) || 3,
        desired_main_characters: Number(mainCharacters) || 5,
        target_total_pages: (targetPages || 'auto').trim() || 'auto',
        genre_tone: mangaGenre || 'Shonen action',
        art_style_reference: artStyle || 'classic black-and-white weekly shonen',
        max_panels_per_page: Number(maxPanelsPerPage) || 6,
        special_requests: specialRequests || 'None',
      });
      const analysis: string = resp.data.analysis || '';
      const breakdown = parseLines(analysis, Math.max(Number(mainCharacters) || 5, 3));
      return {
        characterBreakdown: breakdown.length ? breakdown : ['Character arcs pending parsing.'],
        analysisMarkdown: analysis,
        structuredJson: (resp.data.structured_json as Record<string, unknown>) || null,
      } satisfies Step1Result;
    }

    if (step === 2) {
      const context = getCompactStep1Context();
      const prompt = `You are preparing manga character designs. Use the prior analysis:
${context}

Output global design rules, main character sheets, and supporting cast prompts. Keep concise bullets.`;
      const resp = await geminiApi.generateText(prompt);
      const content: string = resp.data.generated_text || resp.data.analysis || '';
      const lines = parseLines(content, 8);
      const toCharacter = (label: string, text: string, idx: number): Character => ({
        name: `${label} ${idx + 1}`,
        description: text.slice(0, 160) || `Design notes for ${label} ${idx + 1}`,
        imagePrompt: text.slice(0, 140) || `${artStyle} portrait`,
      });
      return {
        globalGuidelines: content.slice(0, 500) || 'Awaiting guidelines',
        mainCharacters: lines.slice(0, 4).map((l, i) => toCharacter('Main', l, i)),
        supportingCharacters: lines.slice(4, 8).map((l, i) => toCharacter('Supporting', l, i)),
      } satisfies Step2Result;
    }

    if (step === 3) {
      const designPrompts = step2.data?.mainCharacters.map((c) => c.imagePrompt).join(' | ') || artStyle;
      const sceneDescription = `Create panel-by-panel script. Style: ${artStyle}. Prompts: ${designPrompts}. Chapters: ${numChapters}.`;
      const resp = await geminiApi.generatePanelScript(sceneDescription);
      const script: string = resp.data.panel_script || resp.data.generated_text || '';
      const pages = Math.min(Number(targetPages) || 30, 12);
      const lines = parseLines(script, 12);
      const scripts: PanelScript[] = Array.from({ length: Math.min(3, pages) }, (_, pageIdx) => ({
        pageNumber: pageIdx + 1,
        layoutSummary: 'Adapted from Gemini panel guidance.',
        panels: lines.slice(pageIdx * 3, pageIdx * 3 + 3).map((line, panelIdx) => ({
          panelNumber: panelIdx + 1,
          description: line || script.slice(0, 120),
          dialogue: '',
          imagePrompt: `${artStyle} panel ${panelIdx + 1}`,
        })),
      }));
      return { totalPages: pages, scripts } satisfies Step3Result;
    }

    const prompt = `Provide ${Math.min(8, Number(targetPages) || 8)} concise image prompts for key panels. Style: ${artStyle}. Use context: ${
      step3.data?.scripts.map((s) => `Page ${s.pageNumber}`).join(', ') || 'story'
    }.`;
    const resp = await geminiApi.generateText(prompt);
    const text: string = resp.data.generated_text || resp.data.analysis || '';
    const prompts = parseLines(text, 8);
    return {
      images: prompts.map((p, i) => ({
        id: `img-${i}`,
        pageNumber: Math.floor(i / 2) + 1,
        panelNumber: (i % 2) + 1,
        prompt: p || `Panel ${i + 1}`,
        imageUrl: `https://via.placeholder.com/360x480?text=Prompt+${i + 1}`,
      })),
    } satisfies Step4Result;
  };

  const getStepCacheKey = (step: StepKey): string => {
    const baseInputs = {
      storyText: storyText.trim(),
      mainCharacters,
      numChapters,
      targetPages,
      mangaGenre,
      artStyle,
      maxPanelsPerPage,
      specialRequests,
    };

    if (step === 1) {
      return JSON.stringify({ step, baseInputs });
    }

    if (step === 2) {
      return JSON.stringify({ step, baseInputs, step1: step1.data });
    }

    if (step === 3) {
      return JSON.stringify({ step, baseInputs, step2: step2.data });
    }

    return JSON.stringify({ step, baseInputs, step3: step3.data });
  };

  const getCooldownSeconds = (step: StepKey): number => {
    const remainingMs = cooldownUntil[step] - nowMs;
    return remainingMs > 0 ? Math.ceil(remainingMs / 1000) : 0;
  };

  const step1JsonStatus = () => {
    if (!step1.data) return 'pending';
    if (step1.isApproved) return 'approved';
    if (step1.isLoading) return 'processing';
    return 'review_pending';
  };

  const projectSnapshot = useMemo(() => {
    const fallbackSnapshot = {
      project_id: projectId || 'manga_project_001',
      project_status: step4.isApproved ? 'completed' : 'in_progress',
      user_inputs: {
        story_content: storyText,
        genre: mangaGenre,
        tone: mangaGenre,
        art_style_reference: artStyle,
        max_panels_per_page: Number(maxPanelsPerPage) || 6,
        user_customizations: {
          special_requests: specialRequests,
        },
      },
      steps: step1.data
        ? {
            step_1_analysis: {
              status: step1JsonStatus(),
              last_updated: step1.lastUpdated,
              data: {
                analysis_markdown: step1.data.analysisMarkdown,
                character_breakdown: step1.data.characterBreakdown,
              },
            },
          }
        : {},
    };

    if (!step1.data?.structuredJson) {
      return fallbackSnapshot;
    }

    const apiSnapshot = step1.data.structuredJson as Record<string, unknown>;
    const apiSteps =
      (apiSnapshot.steps as Record<string, unknown> | undefined) ||
      ({} as Record<string, unknown>);
    const apiStep1 =
      (apiSteps.step_1_analysis as Record<string, unknown> | undefined) ||
      ({} as Record<string, unknown>);

    return {
      ...apiSnapshot,
      project_id: projectId || String(apiSnapshot.project_id || 'manga_project_001'),
      project_status: step4.isApproved ? 'completed' : 'in_progress',
      user_inputs: {
        ...(apiSnapshot.user_inputs as Record<string, unknown> | undefined),
        story_content: storyText,
        genre: mangaGenre,
        tone: mangaGenre,
        art_style_reference: artStyle,
        max_panels_per_page: Number(maxPanelsPerPage) || 6,
        user_customizations: {
          ...(((apiSnapshot.user_inputs as any)?.user_customizations as Record<string, unknown>) || {}),
          special_requests: specialRequests,
        },
      },
      steps: {
        ...apiSteps,
        step_1_analysis: {
          ...apiStep1,
          status: step1JsonStatus(),
          last_updated: step1.lastUpdated,
        },
      },
    };
  }, [
    projectId,
    storyText,
    mangaGenre,
    artStyle,
    maxPanelsPerPage,
    specialRequests,
    step1.data,
    step1.isApproved,
    step1.isLoading,
    step1.lastUpdated,
    step4.isApproved,
  ]);

  useEffect(() => {
    if (typeof window === 'undefined') return;
    window.localStorage.setItem(
      `mohiom-project-${projectSnapshot.project_id}`,
      JSON.stringify(projectSnapshot, null, 2)
    );
  }, [projectSnapshot]);

  const handleGenerate = async (step: StepKey) => {
    if (stepMap[step].locked) return;
    const cooldownSeconds = getCooldownSeconds(step);
    if (cooldownSeconds > 0) {
      setStepState(step, (prev) => ({
        ...prev,
        error: `Rate limited. Retry in ${cooldownSeconds}s.`,
      }));
      return;
    }

    const cacheKey = getStepCacheKey(step);
    const cached = approvedCacheRef.current[step];
    if (cached && cached.key === cacheKey) {
      setStepState(step, (prev) => ({ ...prev, data: cached.data, error: null }));
      setActiveStep(step);
      return;
    }

    setGlobalError(null);
    setStepState(step, (prev) => ({ ...prev, isLoading: true, error: null }));

    try {
      const data = await buildStepPayload(step);
      setStepState(step, (prev) => ({
        ...prev,
        data,
        isLoading: false,
        lastUpdated: new Date().toISOString(),
      }));
      setActiveStep(step);
    } catch (err: unknown) {
      const apiError = toApiError(err);
      const retryAfterSeconds = apiError.retryAfterSeconds;
      if (apiError.status === 429 && typeof retryAfterSeconds === 'number') {
        setCooldownUntil((prev) => ({
          ...prev,
          [step]: Date.now() + retryAfterSeconds * 1000,
        }));
      }

      const retryHint =
        apiError.status === 429 && typeof retryAfterSeconds === 'number'
          ? ` Retry in ${Math.ceil(retryAfterSeconds)}s.`
          : '';

      setStepState(step, (prev) => ({
        ...prev,
        isLoading: false,
        error: `${apiError.message}${retryHint}`.trim(),
      }));
    }
  };

  const handleApprove = (step: StepKey) => {
    const cacheKey = getStepCacheKey(step);
    const data = stepMap[step].data;
    if (data) {
      approvedCacheRef.current[step] = { key: cacheKey, data };
    }

    setStepState(step, (prev) => ({
      ...prev,
      isApproved: true,
      locked: true,
      lastUpdated: new Date().toISOString(),
    }));
    const nextStep = (step + 1) as StepKey;
    if (nextStep <= 4) {
      setStepState(nextStep, (prev) => ({ ...prev, locked: false }));
      setActiveStep(nextStep);
    }
  };

  const handleRetry = (step: StepKey) => {
    setStepState(step, (prev) => ({
      ...prev,
      data: null,
      isApproved: false,
      error: null,
      lastUpdated: null,
    }));
    handleGenerate(step);
  };

  const copyProjectJson = async () => {
    try {
      await navigator.clipboard.writeText(JSON.stringify(projectSnapshot, null, 2));
      setJsonCopied(true);
      window.setTimeout(() => setJsonCopied(false), 1500);
    } catch {
      setGlobalError('Failed to copy JSON to clipboard.');
    }
  };

  const downloadProjectJson = () => {
    try {
      const safeProjectId = (projectSnapshot.project_id || 'manga_project_001')
        .toString()
        .trim()
        .replace(/[^a-zA-Z0-9_-]/g, '_');
      const now = new Date();
      const y = now.getFullYear().toString();
      const m = (now.getMonth() + 1).toString().padStart(2, '0');
      const d = now.getDate().toString().padStart(2, '0');
      const hh = now.getHours().toString().padStart(2, '0');
      const mm = now.getMinutes().toString().padStart(2, '0');
      const versionSuffix = `_${y}${m}${d}_${hh}${mm}`;
      const fileName = `${safeProjectId || 'manga_project_001'}${versionSuffix}.json`;
      const jsonContent = JSON.stringify(projectSnapshot, null, 2);
      const blob = new Blob([jsonContent], { type: 'application/json;charset=utf-8' });
      const url = window.URL.createObjectURL(blob);

      const anchor = document.createElement('a');
      anchor.href = url;
      anchor.download = fileName;
      document.body.appendChild(anchor);
      anchor.click();
      document.body.removeChild(anchor);
      window.URL.revokeObjectURL(url);

      setJsonDownloaded(true);
      window.setTimeout(() => setJsonDownloaded(false), 1500);
    } catch {
      setGlobalError('Failed to download JSON file.');
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setStoryFile(file);
    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      setStoryText(content || '');
    };
    reader.readAsText(file);
  };

  const statusBadge = (step: StepKey) => {
    const s = stepMap[step];
    if (s.isApproved) return 'bg-green-500 text-white';
    if (s.isLoading) return 'bg-blue-500 text-white';
    if (s.locked) return 'bg-slate-600 text-gray-200';
    if (s.data) return 'bg-amber-500 text-slate-900';
    return 'bg-slate-700 text-gray-300';
  };

  const StepCard = ({
    step,
    title,
    children,
    context,
  }: {
    step: StepKey;
    title: string;
    children: React.ReactNode;
    context?: React.ReactNode;
  }) => {
    const state = stepMap[step];
    const locked = state.locked;
    const cooldownSeconds = getCooldownSeconds(step);
    const isCooldown = cooldownSeconds > 0;

    return (
      <div className={`rounded-2xl border ${locked ? 'border-slate-800 bg-slate-900/60' : 'border-slate-700 bg-slate-900'} shadow-lg p-6 space-y-4`}>
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className={`w-10 h-10 flex items-center justify-center rounded-full font-bold ${statusBadge(step)}`}>
              {state.isApproved ? '✓' : step}
            </div>
            <div>
              <p className="text-sm text-gray-400">Step {step}</p>
              <h3 className="text-xl font-semibold text-white">{title}</h3>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <button
              onClick={() => handleGenerate(step)}
              disabled={locked || state.isLoading || isCooldown}
              className={`px-3 py-2 rounded-lg text-sm font-semibold transition ${
                locked || isCooldown
                  ? 'bg-slate-800 text-gray-500 cursor-not-allowed'
                  : 'bg-blue-600 text-white hover:bg-blue-700'
              }`}
            >
              {state.isLoading
                ? 'Generating...'
                : isCooldown
                  ? `Retry in ${cooldownSeconds}s`
                  : `Generate Step ${step}`}
            </button>
            {!state.isApproved && state.data && (
              <button
                onClick={() => handleRetry(step)}
                className="px-3 py-2 rounded-lg text-sm font-semibold bg-slate-700 text-white hover:bg-slate-600"
              >
                Retry Step {step}
              </button>
            )}
            {!state.locked && !state.isApproved && state.data && (
              <button
                onClick={() => handleApprove(step)}
                className="px-3 py-2 rounded-lg text-sm font-semibold bg-green-600 text-white hover:bg-green-700"
              >
                Approve & Next
              </button>
            )}
          </div>
        </div>

        {context && (
          <div className="rounded-xl border border-slate-700 bg-slate-800/60 p-4 text-sm text-gray-200">
            <p className="font-semibold text-gray-100 mb-2">Context from previous step</p>
            {context}
          </div>
        )}

        <div className="rounded-xl bg-slate-800/60 border border-slate-700 p-4 min-h-[160px]">
          {state.error && (
            <div className="mb-3 rounded-md bg-red-900/40 border border-red-600 px-3 py-2 text-red-200 text-sm">
              {state.error}
            </div>
          )}
          {!state.data && !state.isLoading && (
            <p className="text-gray-400 text-sm">No output yet. Generate this step to proceed.</p>
          )}
          {state.isLoading && (
            <div className="flex items-center gap-3 text-blue-200 text-sm">
              <span className="animate-spin">⏳</span>
              Generating...
            </div>
          )}
          {state.data && children}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-950 via-slate-900 to-slate-950 text-white">
      <div className="grid grid-cols-1 xl:grid-cols-[360px_1fr]">
        {/* LEFT: Inputs */}
        <div className="border-r border-slate-800 bg-slate-900/80 p-6 space-y-6">
          <div>
            <h1 className="text-3xl font-bold flex items-center gap-2">
              <span className="text-4xl"></span>
              Text-to-Comic Generator
            </h1>
            <p className="text-sm text-gray-400 mt-1">Sequential review & approval workflow</p>
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-xs text-gray-400 mb-1">Project ID</label>
              <input
                type="text"
                value={projectId}
                onChange={(e) => setProjectId(e.target.value)}
                className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm"
              />
            </div>

            <div>
              <label className="block text-xs uppercase tracking-wide text-gray-400 mb-2">Upload Story</label>
              <input
                type="file"
                accept=".txt,.md,.pdf"
                onChange={handleFileUpload}
                className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm text-white"
              />
              {storyFile && <p className="mt-1 text-xs text-green-400">Loaded {storyFile.name}</p>}
            </div>

            <div>
              <label className="block text-xs uppercase tracking-wide text-gray-400 mb-2">Story Text</label>
              <textarea
                value={storyText}
                onChange={(e) => setStoryText(e.target.value)}
                placeholder="Paste your story here..."
                className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm text-white h-28 resize-none"
              />
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="block text-xs text-gray-400 mb-1">Main Characters</label>
                <input
                  type="number"
                  min={1}
                  max={12}
                  value={mainCharacters}
                  onChange={(e) => setMainCharacters(e.target.value)}
                  className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm"
                />
              </div>
              <div>
                <label className="block text-xs text-gray-400 mb-1">Chapters</label>
                <input
                  type="number"
                  min={1}
                  max={20}
                  value={numChapters}
                  onChange={(e) => setNumChapters(e.target.value)}
                  className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm"
                />
              </div>
              <div>
                <label className="block text-xs text-gray-400 mb-1">Target Pages</label>
                <input
                  type="number"
                  min={1}
                  max={500}
                  value={targetPages}
                  onChange={(e) => setTargetPages(e.target.value)}
                  className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm"
                />
              </div>
              <div>
                <label className="block text-xs text-gray-400 mb-1">Max Panels / Page</label>
                <input
                  type="number"
                  min={1}
                  max={12}
                  value={maxPanelsPerPage}
                  onChange={(e) => setMaxPanelsPerPage(e.target.value)}
                  className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm"
                />
              </div>
            </div>

            <div>
              <label className="block text-xs text-gray-400 mb-1">Genre & Tone</label>
              <input
                type="text"
                value={mangaGenre}
                onChange={(e) => setMangaGenre(e.target.value)}
                className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm"
              />
            </div>

            <div>
              <label className="block text-xs text-gray-400 mb-1">Art Style</label>
              <input
                type="text"
                value={artStyle}
                onChange={(e) => setArtStyle(e.target.value)}
                className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm"
              />
            </div>

            <div>
              <label className="block text-xs text-gray-400 mb-1">Special Requests</label>
              <textarea
                value={specialRequests}
                onChange={(e) => setSpecialRequests(e.target.value)}
                placeholder="e.g. include 3 splash pages, every chapter ends on a cliffhanger"
                className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm text-white h-20 resize-none"
              />
            </div>

            {globalError && (
              <div className="rounded-lg border border-red-500 bg-red-900/40 px-3 py-2 text-sm text-red-100">
                {globalError}
              </div>
            )}

            <div className="rounded-lg border border-slate-700 bg-slate-900/50 p-3 space-y-2">
              <div className="flex items-center justify-between">
                <p className="text-xs uppercase tracking-wide text-gray-400">Saved Project JSON (before/after Step 1)</p>
                <div className="flex items-center gap-2">
                  <button
                    onClick={downloadProjectJson}
                    className="px-2 py-1 rounded-md text-xs font-semibold bg-blue-700 text-white hover:bg-blue-600"
                  >
                    {jsonDownloaded ? 'Downloaded' : 'Download JSON'}
                  </button>
                  <button
                    onClick={copyProjectJson}
                    className="px-2 py-1 rounded-md text-xs font-semibold bg-slate-700 text-white hover:bg-slate-600"
                  >
                    {jsonCopied ? 'Copied' : 'Copy JSON'}
                  </button>
                </div>
              </div>
              <pre className="text-[11px] leading-5 text-gray-200 whitespace-pre-wrap max-h-64 overflow-auto">
                {JSON.stringify(projectSnapshot, null, 2)}
              </pre>
            </div>
          </div>
        </div>

        {/* RIGHT: Steps */}
        <div className="p-8 space-y-6">
          <div className="flex items-center gap-3 text-sm text-gray-400">
            {[1, 2, 3, 4].map((step) => (
              <button
                key={step}
                onClick={() => setActiveStep(step as StepKey)}
                disabled={stepMap[step as StepKey].locked}
                className={`px-3 py-1 rounded-full border text-xs transition ${
                  stepMap[step as StepKey].locked
                    ? 'border-slate-800 text-slate-600'
                    : activeStep === step
                      ? 'border-blue-500 text-blue-200'
                      : 'border-slate-600 text-gray-300 hover:border-blue-400 hover:text-blue-200'
                }`}
              >
                Step {step}
              </button>
            ))}
          </div>

          <StepCard
            step={1}
            title="Analysis & Planning"
          >
            {step1.data && (
              <div className="space-y-4">
                <div>
                  <h4 className="text-sm font-semibold text-gray-100 mb-2">Step 1 API Markdown Response</h4>
                  <div className="max-w-full overflow-x-auto rounded-lg border border-slate-700 bg-slate-900/40 p-4">
                    <div className="prose prose-invert max-w-none text-sm leading-6 [overflow-wrap:anywhere]">
                      <ReactMarkdown
                        remarkPlugins={[remarkGfm]}
                        components={{
                          table: ({ children }) => (
                            <div className="w-full overflow-x-auto">
                              <table className="w-full min-w-[560px] table-auto border-collapse text-sm">{children}</table>
                            </div>
                          ),
                          thead: ({ children }) => <thead className="bg-slate-800/80">{children}</thead>,
                          tbody: ({ children }) => <tbody>{children}</tbody>,
                          tr: ({ children }) => <tr className="border-b border-slate-700">{children}</tr>,
                          th: ({ children }) => (
                            <th className="border border-slate-700 px-3 py-2 text-left font-semibold text-gray-100 align-top">
                              {children}
                            </th>
                          ),
                          td: ({ children }) => (
                            <td className="border border-slate-700 px-3 py-2 text-gray-200 align-top [overflow-wrap:anywhere]">
                              {children}
                            </td>
                          ),
                        }}
                      >
                        {step1.data.analysisMarkdown}
                      </ReactMarkdown>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </StepCard>

          <StepCard
            step={2}
            title="Character Designs"
            context={
              step1.data ? (
                <div className="text-sm text-gray-200 space-y-1">
                  <p>Chapters: {numChapters} • Genre: {mangaGenre}</p>
                  <p>Characters: {step1.data.characterBreakdown.slice(0, 3).join('; ')}...</p>
                </div>
              ) : (
                <p className="text-sm text-gray-400">Approve Step 1 to pass context.</p>
              )
            }
          >
            {step2.data && (
              <div className="space-y-4">
                <div>
                  <h4 className="text-sm font-semibold text-gray-100 mb-2">Global Guidelines</h4>
                  <p className="text-sm text-gray-200 whitespace-pre-wrap">{step2.data.globalGuidelines}</p>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                  {step2.data.mainCharacters.map((c, idx) => (
                    <div key={idx} className="rounded-xl bg-slate-700/50 border border-slate-700 p-3">
                      <p className="text-blue-300 font-semibold">{c.name}</p>
                      <p className="text-sm text-gray-200 mt-1">{c.description}</p>
                      <p className="text-xs text-gray-400 mt-2">Prompt: {c.imagePrompt}</p>
                    </div>
                  ))}
                </div>
                <div>
                  <h4 className="text-sm font-semibold text-gray-100 mb-2">Supporting Cast</h4>
                  <div className="grid grid-cols-2 gap-2 text-sm text-gray-200">
                    {step2.data.supportingCharacters.map((c, idx) => (
                      <div key={idx} className="rounded-lg bg-slate-700/40 px-3 py-2">
                        {c.name}: {c.imagePrompt}
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            )}
          </StepCard>

          <StepCard
            step={3}
            title="Panel-by-Panel Script"
            context={
              step2.data ? (
                <div className="text-sm text-gray-200 space-y-1">
                  <p>Main prompts: {step2.data.mainCharacters.slice(0, 2).map((c) => c.imagePrompt).join(' | ')}...</p>
                  <p>Art style: {artStyle}</p>
                </div>
              ) : (
                <p className="text-sm text-gray-400">Approve Step 2 to pass design context.</p>
              )
            }
          >
            {step3.data && (
              <div className="space-y-4">
                <div className="flex gap-4 text-sm text-gray-200">
                  <span className="rounded-lg bg-slate-700/50 px-3 py-2">Pages: {step3.data.totalPages}</span>
                  <span className="rounded-lg bg-slate-700/50 px-3 py-2">Panels/page ≤ {maxPanelsPerPage}</span>
                </div>
                <div className="space-y-3">
                  {step3.data.scripts.map((script) => (
                    <div key={script.pageNumber} className="rounded-xl border border-slate-700 bg-slate-800/50 p-4 space-y-2">
                      <div className="flex justify-between text-sm text-blue-200 font-semibold">
                        <span>Page {script.pageNumber}</span>
                        <span>{script.layoutSummary}</span>
                      </div>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                        {script.panels.map((panel) => (
                          <div key={panel.panelNumber} className="rounded-lg bg-slate-700/40 p-3 text-sm text-gray-200">
                            <p className="font-semibold text-blue-300">Panel {panel.panelNumber}</p>
                            <p>{panel.description}</p>
                            <p className="text-xs text-gray-400 mt-1">Prompt: {panel.imagePrompt}</p>
                          </div>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </StepCard>

          <StepCard
            step={4}
            title="Image Generation Simulation"
            context={
              step3.data ? (
                <p className="text-sm text-gray-200">Using panel prompts from Step 3 ({step3.data.scripts.length} pages sampled).</p>
              ) : (
                <p className="text-sm text-gray-400">Approve Step 3 to simulate images.</p>
              )
            }
          >
            {step4.data && (
              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
                {step4.data.images.map((img) => (
                  <div key={img.id} className="rounded-xl border border-slate-700 bg-slate-800/60 overflow-hidden group">
                    <div className="aspect-[3/4] bg-slate-700 flex items-center justify-center">
                      <img
                        src={img.imageUrl}
                        alt={img.prompt}
                        className="w-full h-full object-cover group-hover:scale-105 transition-transform"
                      />
                    </div>
                    <div className="p-3 text-xs text-gray-200 space-y-1">
                      <p className="font-semibold text-blue-300">Page {img.pageNumber} · Panel {img.panelNumber}</p>
                      <p className="text-gray-400">{img.prompt}</p>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </StepCard>
        </div>
      </div>
    </div>
  );
}

'use client';

import React, { useEffect, useMemo, useRef, useState } from 'react';
import { geminiApi, toApiError } from '@/services/api';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';

type StepKey = 1 | 2 | 3 | 4;

interface StepState<T> {
  data: T | null;
  isLoading: boolean;
  isApproved: boolean;
  locked: boolean;
  error: string | null;
  lastUpdated: string | null;
}

interface Step1Result {
  characterBreakdown: string[];
  analysisMarkdown: string;
  structuredJson: Record<string, unknown> | null;
}

interface Step2Result {
  designMarkdown: string;
  structuredJson: Record<string, unknown> | null;
  aiPrompts: string[];
}

interface PanelScript {
  pageNumber: number;
  layoutSummary: string;
  panels: {
    panelNumber: number;
    description: string;
    dialogue: string;
    imagePrompt: string;
  }[];
}

interface Step3Result {
  totalPages: number;
  scripts: PanelScript[];
}

interface Step4Result {
  images: {
    id: string;
    pageNumber: number;
    panelNumber: number;
    prompt: string;
    imageUrl: string;
  }[];
}

type StepData = Step1Result | Step2Result | Step3Result | Step4Result;

interface ApprovedCacheEntry {
  key: string;
  data: StepData;
}

const emptyStepState = <T,>(locked: boolean): StepState<T> => ({
  data: null,
  isLoading: false,
  isApproved: false,
  locked,
  error: null,
  lastUpdated: null,
});

export default function TextToComicGenerator() {
  // Input and configuration
  const [projectId, setProjectId] = useState('three_little_pigs_manga_001');
  const [storyFile, setStoryFile] = useState<File | null>(null);
  const [storyText, setStoryText] = useState('');
  const [mainCharacters, setMainCharacters] = useState('5');
  const [numChapters, setNumChapters] = useState('4');
  const [targetPages, setTargetPages] = useState('100');
  const [mangaGenre, setMangaGenre] = useState('Fantasy/Adventure, Epic tone');
  const [artStyle, setArtStyle] = useState('Japanese manga style, detailed');
  const [maxPanelsPerPage, setMaxPanelsPerPage] = useState('6');
  const [specialRequests, setSpecialRequests] = useState('None');

  // Per-step state
  const [step1, setStep1] = useState<StepState<Step1Result>>(emptyStepState(false));
  const [step2, setStep2] = useState<StepState<Step2Result>>(emptyStepState(true));
  const [step3, setStep3] = useState<StepState<Step3Result>>(emptyStepState(true));
  const [step4, setStep4] = useState<StepState<Step4Result>>(emptyStepState(true));
  const [activeStep, setActiveStep] = useState<StepKey>(1);
  const [globalError, setGlobalError] = useState<string | null>(null);
  const [jsonCopied, setJsonCopied] = useState(false);
  const [jsonDownloaded, setJsonDownloaded] = useState(false);
  const [lastDownloadedJsonFile, setLastDownloadedJsonFile] = useState<string | null>(null);
  const [cooldownUntil, setCooldownUntil] = useState<Record<StepKey, number>>({
    1: 0,
    2: 0,
    3: 0,
    4: 0,
  });
  const [nowMs, setNowMs] = useState<number>(Date.now());
  const approvedCacheRef = useRef<Partial<Record<StepKey, ApprovedCacheEntry>>>({});

  useEffect(() => {
    const timer = window.setInterval(() => setNowMs(Date.now()), 1000);
    return () => window.clearInterval(timer);
  }, []);

  const stepMap: Record<StepKey, StepState<any>> = useMemo(
    () => ({ 1: step1, 2: step2, 3: step3, 4: step4 }),
    [step1, step2, step3, step4]
  );

  const setStepState = (step: StepKey, updater: (prev: StepState<any>) => StepState<any>) => {
    if (step === 1) setStep1((prev) => updater(prev));
    if (step === 2) setStep2((prev) => updater(prev));
    if (step === 3) setStep3((prev) => updater(prev));
    if (step === 4) setStep4((prev) => updater(prev));
  };

  const parseLines = (text: string, limit: number) =>
    text
      .split(/\r?\n+/)
      .map((line) => line.replace(/^[-*\d.\s]+/, '').trim())
      .filter(Boolean)
      .slice(0, limit);

  const getStep1StructuredJson = (): Record<string, unknown> => {
    if (step1.data?.structuredJson) {
      return step1.data.structuredJson;
    }

    return {
      project_id: projectId,
      project_status: 'in_progress',
      user_inputs: {
        story_content: storyText,
        genre: mangaGenre,
        tone: mangaGenre,
        art_style_reference: artStyle,
        max_panels_per_page: Number(maxPanelsPerPage) || 6,
        user_customizations: { special_requests: specialRequests },
      },
      steps: {
        step_1_analysis: {
          status: step1.isApproved ? 'approved' : 'review_pending',
          last_updated: step1.lastUpdated,
          data: {
            analysis_markdown: step1.data?.analysisMarkdown || '',
          },
        },
      },
    };
  };

  const getStep2PromptList = (): string[] => {
    const steps = (step2.data?.structuredJson as any)?.steps;
    const mainDesigns = steps?.step_2_design?.data?.main_characters_designs;
    if (!mainDesigns || typeof mainDesigns !== 'object') {
      return step2.data?.aiPrompts || [];
    }

    return Object.values(mainDesigns)
      .map((entry: any) => entry?.ai_image_prompt_ready)
      .filter((value: unknown): value is string => typeof value === 'string' && value.trim().length > 0);
  };

  const buildStepPayload = async (step: StepKey): Promise<Step1Result | Step2Result | Step3Result | Step4Result> => {
    if (!storyText.trim()) {
      throw new Error('Please provide story text before generating.');
    }

    if (step === 1) {
      const resp = await geminiApi.analyzeStoryStructured({
        project_id: projectId,
        story_text: storyText,
        num_chapters: Number(numChapters) || 3,
        desired_main_characters: Number(mainCharacters) || 5,
        target_total_pages: (targetPages || 'auto').trim() || 'auto',
        genre_tone: mangaGenre || 'Shonen action',
        art_style_reference: artStyle || 'classic black-and-white weekly shonen',
        max_panels_per_page: Number(maxPanelsPerPage) || 6,
        special_requests: specialRequests || 'None',
      });
      const analysis: string = resp.data.analysis || '';
      const breakdown = parseLines(analysis, Math.max(Number(mainCharacters) || 5, 3));
      return {
        characterBreakdown: breakdown.length ? breakdown : ['Character arcs pending parsing.'],
        analysisMarkdown: analysis,
        structuredJson: (resp.data.structured_json as Record<string, unknown>) || null,
      } satisfies Step1Result;
    }

    if (step === 2) {
      const resp = await geminiApi.generateCharacterDesignsStructured({
        project_id: projectId,
        step1_json: getStep1StructuredJson(),
        desired_main_characters: Number(mainCharacters) || 5,
        genre_tone: mangaGenre || 'Shonen action',
        art_style_reference: artStyle || 'classic black-and-white weekly shonen',
        special_requests: specialRequests || 'None',
      });

      const designMarkdown: string = resp.data.design_markdown || '';
      const structuredJson = (resp.data.structured_json as Record<string, unknown>) || null;
      const mainDesigns = ((structuredJson as any)?.steps?.step_2_design?.data?.main_characters_designs || {}) as Record<
        string,
        { ai_image_prompt_ready?: string }
      >;
      const aiPrompts = Object.values(mainDesigns)
        .map((entry) => entry?.ai_image_prompt_ready)
        .filter((prompt): prompt is string => typeof prompt === 'string' && prompt.trim().length > 0);

      return {
        designMarkdown,
        structuredJson,
        aiPrompts,
      } satisfies Step2Result;
    }

    if (step === 3) {
      const designPrompts = getStep2PromptList().join(' | ') || artStyle;
      const sceneDescription = `Create panel-by-panel script. Style: ${artStyle}. Prompts: ${designPrompts}. Chapters: ${numChapters}.`;
      const resp = await geminiApi.generatePanelScript(sceneDescription);
      const script: string = resp.data.panel_script || resp.data.generated_text || '';
      const pages = Math.min(Number(targetPages) || 30, 12);
      const lines = parseLines(script, 12);
      const scripts: PanelScript[] = Array.from({ length: Math.min(3, pages) }, (_, pageIdx) => ({
        pageNumber: pageIdx + 1,
        layoutSummary: 'Adapted from Gemini panel guidance.',
        panels: lines.slice(pageIdx * 3, pageIdx * 3 + 3).map((line, panelIdx) => ({
          panelNumber: panelIdx + 1,
          description: line || script.slice(0, 120),
          dialogue: '',
          imagePrompt: `${artStyle} panel ${panelIdx + 1}`,
        })),
      }));
      return { totalPages: pages, scripts } satisfies Step3Result;
    }

    const prompt = `Provide ${Math.min(8, Number(targetPages) || 8)} concise image prompts for key panels. Style: ${artStyle}. Use context: ${
      step3.data?.scripts.map((s) => `Page ${s.pageNumber}`).join(', ') || 'story'
    }.`;
    const resp = await geminiApi.generateText(prompt);
    const text: string = resp.data.generated_text || resp.data.analysis || '';
    const prompts = parseLines(text, 8);
    return {
      images: prompts.map((p, i) => ({
        id: `img-${i}`,
        pageNumber: Math.floor(i / 2) + 1,
        panelNumber: (i % 2) + 1,
        prompt: p || `Panel ${i + 1}`,
        imageUrl: `https://via.placeholder.com/360x480?text=Prompt+${i + 1}`,
      })),
    } satisfies Step4Result;
  };

  const getStepCacheKey = (step: StepKey): string => {
    const baseInputs = {
      storyText: storyText.trim(),
      mainCharacters,
      numChapters,
      targetPages,
      mangaGenre,
      artStyle,
      maxPanelsPerPage,
      specialRequests,
    };

    if (step === 1) {
      return JSON.stringify({ step, baseInputs });
    }

    if (step === 2) {
      return JSON.stringify({ step, baseInputs, step1: step1.data });
    }

    if (step === 3) {
      return JSON.stringify({ step, baseInputs, step2: step2.data });
    }

    return JSON.stringify({ step, baseInputs, step3: step3.data });
  };

  const getCooldownSeconds = (step: StepKey): number => {
    const remainingMs = cooldownUntil[step] - nowMs;
    return remainingMs > 0 ? Math.ceil(remainingMs / 1000) : 0;
  };

  const step1JsonStatus = () => {
    if (!step1.data) return 'pending';
    if (step1.isApproved) return 'approved';
    if (step1.isLoading) return 'processing';
    return 'review_pending';
  };

  const projectSnapshot = useMemo(() => {
    const fallbackSnapshot = {
      project_id: projectId || 'manga_project_001',
      project_status: step4.isApproved ? 'completed' : 'in_progress',
      user_inputs: {
        story_content: storyText,
        genre: mangaGenre,
        tone: mangaGenre,
        art_style_reference: artStyle,
        max_panels_per_page: Number(maxPanelsPerPage) || 6,
        user_customizations: {
          special_requests: specialRequests,
        },
      },
      steps: step1.data
        ? {
            step_1_analysis: {
              status: step1JsonStatus(),
              last_updated: step1.lastUpdated,
              data: {
                analysis_markdown: step1.data.analysisMarkdown,
                character_breakdown: step1.data.characterBreakdown,
              },
            },
          }
        : {},
    };

    if (!step1.data?.structuredJson && !step2.data?.structuredJson) {
      return fallbackSnapshot;
    }

    const apiSnapshot =
      (step2.data?.structuredJson as Record<string, unknown>) ||
      (step1.data?.structuredJson as Record<string, unknown>);
    const apiSteps =
      (apiSnapshot.steps as Record<string, unknown> | undefined) ||
      ({} as Record<string, unknown>);
    const apiStep1 =
      (apiSteps.step_1_analysis as Record<string, unknown> | undefined) ||
      ({} as Record<string, unknown>);

    const apiStep2 =
      (apiSteps.step_2_design as Record<string, unknown> | undefined) ||
      ({} as Record<string, unknown>);

    return {
      ...apiSnapshot,
      project_id: projectId || String(apiSnapshot.project_id || 'manga_project_001'),
      project_status: step4.isApproved ? 'completed' : 'in_progress',
      user_inputs: {
        ...(apiSnapshot.user_inputs as Record<string, unknown> | undefined),
        story_content: storyText,
        genre: mangaGenre,
        tone: mangaGenre,
        art_style_reference: artStyle,
        max_panels_per_page: Number(maxPanelsPerPage) || 6,
        user_customizations: {
          ...(((apiSnapshot.user_inputs as any)?.user_customizations as Record<string, unknown>) || {}),
          special_requests: specialRequests,
        },
      },
      steps: {
        ...apiSteps,
        step_1_analysis: {
          ...apiStep1,
          status: step1JsonStatus(),
          last_updated: step1.lastUpdated,
        },
        ...(step2.data
          ? {
              step_2_design: {
                ...apiStep2,
                status: step2.isApproved ? 'approved' : step2.isLoading ? 'processing' : 'review_pending',
                last_updated: step2.lastUpdated,
                data: {
                  ...((apiStep2.data as Record<string, unknown> | undefined) || {}),
                  design_markdown: step2.data.designMarkdown,
                },
              },
            }
          : {}),
      },
    };
  }, [
    projectId,
    storyText,
    mangaGenre,
    artStyle,
    maxPanelsPerPage,
    specialRequests,
    step1.data,
    step1.isApproved,
    step1.isLoading,
    step1.lastUpdated,
    step2.data,
    step2.isApproved,
    step2.isLoading,
    step2.lastUpdated,
    step4.isApproved,
  ]);

  useEffect(() => {
    if (typeof window === 'undefined') return;
    window.localStorage.setItem(
      `mohiom-project-${projectSnapshot.project_id}`,
      JSON.stringify(projectSnapshot, null, 2)
    );
  }, [projectSnapshot]);

  const handleGenerate = async (step: StepKey) => {
    if (stepMap[step].locked) return;
    const cooldownSeconds = getCooldownSeconds(step);
    if (cooldownSeconds > 0) {
      setStepState(step, (prev) => ({
        ...prev,
        error: `Rate limited. Retry in ${cooldownSeconds}s.`,
      }));
      return;
    }

    const cacheKey = getStepCacheKey(step);
    const cached = approvedCacheRef.current[step];
    if (cached && cached.key === cacheKey) {
      setStepState(step, (prev) => ({ ...prev, data: cached.data, error: null }));
      setActiveStep(step);
      return;
    }

    setGlobalError(null);
    setStepState(step, (prev) => ({ ...prev, isLoading: true, error: null }));

    try {
      const data = await buildStepPayload(step);
      setStepState(step, (prev) => ({
        ...prev,
        data,
        isLoading: false,
        lastUpdated: new Date().toISOString(),
      }));
      setActiveStep(step);
    } catch (err: unknown) {
      const apiError = toApiError(err);
      const retryAfterSeconds = apiError.retryAfterSeconds;
      if (apiError.status === 429 && typeof retryAfterSeconds === 'number') {
        setCooldownUntil((prev) => ({
          ...prev,
          [step]: Date.now() + retryAfterSeconds * 1000,
        }));
      }

      const retryHint =
        apiError.status === 429 && typeof retryAfterSeconds === 'number'
          ? ` Retry in ${Math.ceil(retryAfterSeconds)}s.`
          : '';

      setStepState(step, (prev) => ({
        ...prev,
        isLoading: false,
        error: `${apiError.message}${retryHint}`.trim(),
      }));
    }
  };

  const handleApprove = (step: StepKey) => {
    const cacheKey = getStepCacheKey(step);
    const data = stepMap[step].data;
    if (data) {
      approvedCacheRef.current[step] = { key: cacheKey, data };
    }

    setStepState(step, (prev) => ({
      ...prev,
      isApproved: true,
      locked: true,
      lastUpdated: new Date().toISOString(),
    }));
    const nextStep = (step + 1) as StepKey;
    if (nextStep <= 4) {
      setStepState(nextStep, (prev) => ({ ...prev, locked: false }));
      setActiveStep(nextStep);
    }
  };

  const handleRetry = (step: StepKey) => {
    setStepState(step, (prev) => ({
      ...prev,
      data: null,
      isApproved: false,
      error: null,
      lastUpdated: null,
    }));
    handleGenerate(step);
  };

  const copyProjectJson = async () => {
    try {
      await navigator.clipboard.writeText(JSON.stringify(projectSnapshot, null, 2));
      setJsonCopied(true);
      window.setTimeout(() => setJsonCopied(false), 1500);
    } catch {
      setGlobalError('Failed to copy JSON to clipboard.');
    }
  };

  const downloadProjectJson = () => {
    try {
      const safeProjectId = (projectSnapshot.project_id || 'manga_project_001')
        .toString()
        .trim()
        .replace(/[^a-zA-Z0-9_-]/g, '_');
      const now = new Date();
      const y = now.getFullYear().toString();
      const m = (now.getMonth() + 1).toString().padStart(2, '0');
      const d = now.getDate().toString().padStart(2, '0');
      const hh = now.getHours().toString().padStart(2, '0');
      const mm = now.getMinutes().toString().padStart(2, '0');
      const versionSuffix = `_${y}${m}${d}_${hh}${mm}`;
      const fileName = `${safeProjectId || 'manga_project_001'}${versionSuffix}.json`;
      const jsonContent = JSON.stringify(projectSnapshot, null, 2);
      const blob = new Blob([jsonContent], { type: 'application/json;charset=utf-8' });
      const url = window.URL.createObjectURL(blob);

      const anchor = document.createElement('a');
      anchor.href = url;
      anchor.download = fileName;
      document.body.appendChild(anchor);
      anchor.click();
      document.body.removeChild(anchor);
      window.URL.revokeObjectURL(url);

      setJsonDownloaded(true);
      setLastDownloadedJsonFile(fileName);
      window.setTimeout(() => setJsonDownloaded(false), 1500);
    } catch {
      setGlobalError('Failed to download JSON file.');
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setStoryFile(file);
    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      setStoryText(content || '');
    };
    reader.readAsText(file);
  };

  const statusBadge = (step: StepKey) => {
    const s = stepMap[step];
    if (s.isApproved) return 'bg-green-500 text-white';
    if (s.isLoading) return 'bg-blue-500 text-white';
    if (s.locked) return 'bg-slate-600 text-gray-200';
    if (s.data) return 'bg-amber-500 text-slate-900';
    return 'bg-slate-700 text-gray-300';
  };

  const StepCard = ({
    step,
    title,
    children,
    context,
  }: {
    step: StepKey;
    title: string;
    children: React.ReactNode;
    context?: React.ReactNode;
  }) => {
    const state = stepMap[step];
    const locked = state.locked;
    const cooldownSeconds = getCooldownSeconds(step);
    const isCooldown = cooldownSeconds > 0;

    return (
      <div className={`rounded-2xl border ${locked ? 'border-slate-800 bg-slate-900/60' : 'border-slate-700 bg-slate-900'} shadow-lg p-6 space-y-4`}>
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className={`w-10 h-10 flex items-center justify-center rounded-full font-bold ${statusBadge(step)}`}>
              {state.isApproved ? '✓' : step}
            </div>
            <div>
              <p className="text-sm text-gray-400">Step {step}</p>
              <h3 className="text-xl font-semibold text-white">{title}</h3>
            </div>
          </div>
          <div className="flex items-center gap-2">
            <button
              onClick={() => handleGenerate(step)}
              disabled={locked || state.isLoading || isCooldown}
              className={`px-3 py-2 rounded-lg text-sm font-semibold transition ${
                locked || isCooldown
                  ? 'bg-slate-800 text-gray-500 cursor-not-allowed'
                  : 'bg-blue-600 text-white hover:bg-blue-700'
              }`}
            >
              {state.isLoading
                ? 'Generating...'
                : isCooldown
                  ? `Retry in ${cooldownSeconds}s`
                  : `Generate Step ${step}`}
            </button>
            {!state.isApproved && state.data && (
              <button
                onClick={() => handleRetry(step)}
                className="px-3 py-2 rounded-lg text-sm font-semibold bg-slate-700 text-white hover:bg-slate-600"
              >
                Retry Step {step}
              </button>
            )}
            {!state.locked && !state.isApproved && state.data && (
              <button
                onClick={() => handleApprove(step)}
                className="px-3 py-2 rounded-lg text-sm font-semibold bg-green-600 text-white hover:bg-green-700"
              >
                Approve & Next
              </button>
            )}
          </div>
        </div>

        {context && (
          <div className="rounded-xl border border-slate-700 bg-slate-800/60 p-4 text-sm text-gray-200">
            <p className="font-semibold text-gray-100 mb-2">Context from previous step</p>
            {context}
          </div>
        )}

        <div className="rounded-xl bg-slate-800/60 border border-slate-700 p-4 min-h-[160px]">
          {state.error && (
            <div className="mb-3 rounded-md bg-red-900/40 border border-red-600 px-3 py-2 text-red-200 text-sm">
              {state.error}
            </div>
          )}
          {!state.data && !state.isLoading && (
            <p className="text-gray-400 text-sm">No output yet. Generate this step to proceed.</p>
          )}
          {state.isLoading && (
            <div className="flex items-center gap-3 text-blue-200 text-sm">
              <span className="animate-spin">⏳</span>
              Generating...
            </div>
          )}
          {state.data && children}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-950 via-slate-900 to-slate-950 text-white">
      <div className="grid grid-cols-1 xl:grid-cols-[360px_1fr]">
        {/* LEFT: Inputs */}
        <div className="border-r border-slate-800 bg-slate-900/80 p-6 space-y-6">
          <div>
            <h1 className="text-3xl font-bold flex items-center gap-2">
              <span className="text-4xl"></span>
              Text-to-Comic Generator
            </h1>
            <p className="text-sm text-gray-400 mt-1">Sequential review & approval workflow</p>
          </div>

          <div className="space-y-4">
            <div>
              <label className="block text-xs text-gray-400 mb-1">Project ID</label>
              <input
                type="text"
                value={projectId}
                onChange={(e) => setProjectId(e.target.value)}
                className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm"
              />
            </div>

            <div>
              <label className="block text-xs uppercase tracking-wide text-gray-400 mb-2">Upload Story</label>
              <input
                type="file"
                accept=".txt,.md,.pdf"
                onChange={handleFileUpload}
                className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm text-white"
              />
              {storyFile && <p className="mt-1 text-xs text-green-400">Loaded {storyFile.name}</p>}
            </div>

            <div>
              <label className="block text-xs uppercase tracking-wide text-gray-400 mb-2">Story Text</label>
              <textarea
                value={storyText}
                onChange={(e) => setStoryText(e.target.value)}
                placeholder="Paste your story here..."
                className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm text-white h-28 resize-none"
              />
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div>
                <label className="block text-xs text-gray-400 mb-1">Main Characters</label>
                <input
                  type="number"
                  min={1}
                  max={12}
                  value={mainCharacters}
                  onChange={(e) => setMainCharacters(e.target.value)}
                  className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm"
                />
              </div>
              <div>
                <label className="block text-xs text-gray-400 mb-1">Chapters</label>
                <input
                  type="number"
                  min={1}
                  max={20}
                  value={numChapters}
                  onChange={(e) => setNumChapters(e.target.value)}
                  className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm"
                />
              </div>
              <div>
                <label className="block text-xs text-gray-400 mb-1">Target Pages</label>
                <input
                  type="number"
                  min={1}
                  max={500}
                  value={targetPages}
                  onChange={(e) => setTargetPages(e.target.value)}
                  className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm"
                />
              </div>
              <div>
                <label className="block text-xs text-gray-400 mb-1">Max Panels / Page</label>
                <input
                  type="number"
                  min={1}
                  max={12}
                  value={maxPanelsPerPage}
                  onChange={(e) => setMaxPanelsPerPage(e.target.value)}
                  className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm"
                />
              </div>
            </div>

            <div>
              <label className="block text-xs text-gray-400 mb-1">Genre & Tone</label>
              <input
                type="text"
                value={mangaGenre}
                onChange={(e) => setMangaGenre(e.target.value)}
                className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm"
              />
            </div>

            <div>
              <label className="block text-xs text-gray-400 mb-1">Art Style</label>
              <input
                type="text"
                value={artStyle}
                onChange={(e) => setArtStyle(e.target.value)}
                className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm"
              />
            </div>

            <div>
              <label className="block text-xs text-gray-400 mb-1">Special Requests</label>
              <textarea
                value={specialRequests}
                onChange={(e) => setSpecialRequests(e.target.value)}
                placeholder="e.g. include 3 splash pages, every chapter ends on a cliffhanger"
                className="w-full rounded-lg border border-slate-700 bg-slate-800 px-3 py-2 text-sm text-white h-20 resize-none"
              />
            </div>

            {globalError && (
              <div className="rounded-lg border border-red-500 bg-red-900/40 px-3 py-2 text-sm text-red-100">
                {globalError}
              </div>
            )}

            <div className="rounded-lg border border-slate-700 bg-slate-900/50 p-3 space-y-2">
              <div className="flex items-center justify-between">
                <p className="text-xs uppercase tracking-wide text-gray-400">Saved Project JSON (before/after Step 1)</p>
                <div className="flex items-center gap-2">
                  <button
                    onClick={downloadProjectJson}
                    className="px-2 py-1 rounded-md text-xs font-semibold bg-blue-700 text-white hover:bg-blue-600"
                  >
                    {jsonDownloaded ? 'Downloaded' : 'Download JSON'}
                  </button>
                  <button
                    onClick={copyProjectJson}
                    className="px-2 py-1 rounded-md text-xs font-semibold bg-slate-700 text-white hover:bg-slate-600"
                  >
                    {jsonCopied ? 'Copied' : 'Copy JSON'}
                  </button>
                </div>
              </div>
              <pre className="text-[11px] leading-5 text-gray-200 whitespace-pre-wrap max-h-64 overflow-auto">
                {JSON.stringify(projectSnapshot, null, 2)}
              </pre>
              {lastDownloadedJsonFile && (
                <p className="text-[11px] text-green-300">
                  Last downloaded: <span className="font-semibold">{lastDownloadedJsonFile}</span>
                </p>
              )}
            </div>
          </div>
        </div>

        {/* RIGHT: Steps */}
        <div className="p-8 space-y-6">
          <div className="flex items-center gap-3 text-sm text-gray-400">
            {[1, 2, 3, 4].map((step) => (
              <button
                key={step}
                onClick={() => setActiveStep(step as StepKey)}
                disabled={stepMap[step as StepKey].locked}
                className={`px-3 py-1 rounded-full border text-xs transition ${
                  stepMap[step as StepKey].locked
                    ? 'border-slate-800 text-slate-600'
                    : activeStep === step
                      ? 'border-blue-500 text-blue-200'
                      : 'border-slate-600 text-gray-300 hover:border-blue-400 hover:text-blue-200'
                }`}
              >
                Step {step}
              </button>
            ))}
          </div>

          <StepCard
            step={1}
            title="Analysis & Planning"
          >
            {step1.data && (
              <div className="space-y-4">
                <div>
                  <h4 className="text-sm font-semibold text-gray-100 mb-2">Step 1 API Markdown Response</h4>
                  <div className="max-w-full overflow-x-auto rounded-lg border border-slate-700 bg-slate-900/40 p-4">
                    <div className="prose prose-invert max-w-none text-sm leading-6 [overflow-wrap:anywhere]">
                      <ReactMarkdown
                        remarkPlugins={[remarkGfm]}
                        components={{
                          table: ({ children }) => (
                            <div className="w-full overflow-x-auto">
                              <table className="w-full min-w-[560px] table-auto border-collapse text-sm">{children}</table>
                            </div>
                          ),
                          thead: ({ children }) => <thead className="bg-slate-800/80">{children}</thead>,
                          tbody: ({ children }) => <tbody>{children}</tbody>,
                          tr: ({ children }) => <tr className="border-b border-slate-700">{children}</tr>,
                          th: ({ children }) => (
                            <th className="border border-slate-700 px-3 py-2 text-left font-semibold text-gray-100 align-top">
                              {children}
                            </th>
                          ),
                          td: ({ children }) => (
                            <td className="border border-slate-700 px-3 py-2 text-gray-200 align-top [overflow-wrap:anywhere]">
                              {children}
                            </td>
                          ),
                        }}
                      >
                        {step1.data.analysisMarkdown}
                      </ReactMarkdown>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </StepCard>

          <StepCard
            step={2}
            title="Character Designs"
            context={
              step1.data ? (
                <div className="text-sm text-gray-200 space-y-1">
                  <p>Chapters: {numChapters} • Genre: {mangaGenre}</p>
                  <p>Characters: {step1.data.characterBreakdown.slice(0, 3).join('; ')}...</p>
                </div>
              ) : (
                <p className="text-sm text-gray-400">Approve Step 1 to pass context.</p>
              )
            }
          >
            {step2.data && (
              <div className="space-y-4">
                <div>
                  <h4 className="text-sm font-semibold text-gray-100 mb-2">Step 2 API Markdown Response</h4>
                  <div className="max-w-full overflow-x-auto rounded-lg border border-slate-700 bg-slate-900/40 p-4">
                    <div className="prose prose-invert max-w-none text-sm leading-6 [overflow-wrap:anywhere]">
                      <ReactMarkdown
                        remarkPlugins={[remarkGfm]}
                        components={{
                          table: ({ children }) => (
                            <div className="w-full overflow-x-auto">
                              <table className="w-full min-w-[560px] table-auto border-collapse text-sm">{children}</table>
                            </div>
                          ),
                          thead: ({ children }) => <thead className="bg-slate-800/80">{children}</thead>,
                          tbody: ({ children }) => <tbody>{children}</tbody>,
                          tr: ({ children }) => <tr className="border-b border-slate-700">{children}</tr>,
                          th: ({ children }) => (
                            <th className="border border-slate-700 px-3 py-2 text-left font-semibold text-gray-100 align-top">
                              {children}
                            </th>
                          ),
                          td: ({ children }) => (
                            <td className="border border-slate-700 px-3 py-2 text-gray-200 align-top [overflow-wrap:anywhere]">
                              {children}
                            </td>
                          ),
                        }}
                      >
                        {step2.data.designMarkdown}
                      </ReactMarkdown>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </StepCard>

          <StepCard
            step={3}
            title="Panel-by-Panel Script"
            context={
              step2.data ? (
                <div className="text-sm text-gray-200 space-y-1">
                  <p>Main prompts: {getStep2PromptList().slice(0, 2).join(' | ') || 'Using Step 2 design context'}...</p>
                  <p>Art style: {artStyle}</p>
                </div>
              ) : (
                <p className="text-sm text-gray-400">Approve Step 2 to pass design context.</p>
              )
            }
          >
            {step3.data && (
              <div className="space-y-4">
                <div className="flex gap-4 text-sm text-gray-200">
                  <span className="rounded-lg bg-slate-700/50 px-3 py-2">Pages: {step3.data.totalPages}</span>
                  <span className="rounded-lg bg-slate-700/50 px-3 py-2">Panels/page ≤ {maxPanelsPerPage}</span>
                </div>
                <div className="space-y-3">
                  {step3.data.scripts.map((script) => (
                    <div key={script.pageNumber} className="rounded-xl border border-slate-700 bg-slate-800/50 p-4 space-y-2">
                      <div className="flex justify-between text-sm text-blue-200 font-semibold">
                        <span>Page {script.pageNumber}</span>
                        <span>{script.layoutSummary}</span>
                      </div>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
                        {script.panels.map((panel) => (
                          <div key={panel.panelNumber} className="rounded-lg bg-slate-700/40 p-3 text-sm text-gray-200">
                            <p className="font-semibold text-blue-300">Panel {panel.panelNumber}</p>
                            <p>{panel.description}</p>
                            <p className="text-xs text-gray-400 mt-1">Prompt: {panel.imagePrompt}</p>
                          </div>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </StepCard>

          <StepCard
            step={4}
            title="Image Generation Simulation"
            context={
              step3.data ? (
                <p className="text-sm text-gray-200">Using panel prompts from Step 3 ({step3.data.scripts.length} pages sampled).</p>
              ) : (
                <p className="text-sm text-gray-400">Approve Step 3 to simulate images.</p>
              )
            }
          >
            {step4.data && (
              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4">
                {step4.data.images.map((img) => (
                  <div key={img.id} className="rounded-xl border border-slate-700 bg-slate-800/60 overflow-hidden group">
                    <div className="aspect-[3/4] bg-slate-700 flex items-center justify-center">
                      <img
                        src={img.imageUrl}
                        alt={img.prompt}
                        className="w-full h-full object-cover group-hover:scale-105 transition-transform"
                      />
                    </div>
                    <div className="p-3 text-xs text-gray-200 space-y-1">
                      <p className="font-semibold text-blue-300">Page {img.pageNumber} · Panel {img.panelNumber}</p>
                      <p className="text-gray-400">{img.prompt}</p>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </StepCard>
        </div>
      </div>
    </div>
  );
}

import axios from "axios";

const API_BASE_URL = process.env.NEXT_PUBLIC_API_URL || "http://localhost:8000/api";

export const apiClient = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    "Content-Type": "application/json",
  },
});

const API_LOGGING_ENABLED =
  typeof window !== "undefined" &&
  (process.env.NEXT_PUBLIC_API_LOGGING || "true").toLowerCase() !== "false";

const redactHeaders = (headers: unknown): unknown => {
  if (!headers || typeof headers !== "object") return headers;

  const blockedKeys = new Set(["authorization", "cookie", "set-cookie", "x-api-key"]);
  const safe: Record<string, unknown> = {};

  for (const [key, value] of Object.entries(headers as Record<string, unknown>)) {
    safe[key] = blockedKeys.has(key.toLowerCase()) ? "[REDACTED]" : value;
  }

  return safe;
};

const fullUrl = (baseURL: string | undefined, url: string | undefined): string => {
  if (!url) return baseURL || "";
  if (/^https?:\/\//i.test(url)) return url;
  return `${baseURL || ""}${url}`;
};

const USER_ID_STORAGE_KEY = "mohiom-user-id";

const getOrCreateUserId = (): string => {
  if (typeof window === "undefined") return "server";
  const existing = window.localStorage.getItem(USER_ID_STORAGE_KEY);
  if (existing) return existing;

  const next =
    typeof window.crypto !== "undefined" && "randomUUID" in window.crypto
      ? window.crypto.randomUUID()
      : `user-${Date.now()}-${Math.random().toString(16).slice(2)}`;

  window.localStorage.setItem(USER_ID_STORAGE_KEY, next);
  return next;
};

apiClient.interceptors.request.use((config) => {
  config.headers = config.headers || {};
  config.headers["X-User-Id"] = getOrCreateUserId();

  (config as any).metadata = { startedAt: Date.now() };

  if (API_LOGGING_ENABLED) {
    const method = (config.method || "GET").toUpperCase();
    const url = fullUrl(config.baseURL, config.url);
    console.groupCollapsed(`API REQUEST ${method} ${url}`);
    console.log("method:", method);
    console.log("url:", url);
    console.log("params:", config.params ?? null);
    console.log("headers:", redactHeaders(config.headers));
    console.log("data:", config.data ?? null);
    console.groupEnd();
  }

  return config;
});

apiClient.interceptors.response.use(
  (response) => {
    if (API_LOGGING_ENABLED) {
      const config: any = response.config || {};
      const method = (config.method || "GET").toUpperCase();
      const url = fullUrl(config.baseURL, config.url);
      const startedAt = config.metadata?.startedAt || Date.now();
      const durationMs = Date.now() - startedAt;

      console.groupCollapsed(`API RESPONSE ${response.status} ${method} ${url}`);
      console.log("status:", response.status);
      console.log("durationMs:", durationMs);
      console.log("headers:", redactHeaders(response.headers));
      console.log("data:", response.data ?? null);
      console.groupEnd();
    }

    return response;
  },
  (error) => {
    if (API_LOGGING_ENABLED && axios.isAxiosError(error)) {
      const config: any = error.config || {};
      const method = (config.method || "GET").toUpperCase();
      const url = fullUrl(config.baseURL, config.url);
      const startedAt = config.metadata?.startedAt || Date.now();
      const durationMs = Date.now() - startedAt;

      console.groupCollapsed(
        `API ERROR ${error.response?.status || "NO_STATUS"} ${method} ${url}`
      );
      console.log("message:", error.message);
      console.log("status:", error.response?.status ?? null);
      console.log("durationMs:", durationMs);
      console.log("requestHeaders:", redactHeaders(config.headers));
      console.log("requestData:", config.data ?? null);
      console.log("responseHeaders:", redactHeaders(error.response?.headers));
      console.log("responseData:", error.response?.data ?? null);
      console.groupEnd();
    }

    return Promise.reject(error);
  }
);

export interface ApiErrorInfo {
  status: number;
  message: string;
  retryAfterSeconds?: number;
}

export interface AnalyzeStoryPayload {
  story_text: string;
  num_chapters: number;
  desired_main_characters: number;
  target_total_pages: string;
  genre_tone: string;
  art_style_reference: string;
  max_panels_per_page: number;
  special_requests: string;
  project_id?: string;
}

export interface AnalyzeStoryStructuredResponse {
  analysis: string;
  structured_json: Record<string, unknown>;
}

export const toApiError = (error: unknown): ApiErrorInfo => {
  if (axios.isAxiosError(error)) {
    const status = error.response?.status ?? 0;
    const detail = error.response?.data?.detail;
    const message =
      typeof detail === "string"
        ? detail
        : detail?.message || error.message || "Request failed";

    const retryFromDetail =
      typeof detail?.retry_after_seconds === "number"
        ? detail.retry_after_seconds
        : undefined;
    const retryFromHeaderRaw = error.response?.headers?.["retry-after"];
    const retryFromHeader = retryFromHeaderRaw
      ? Number(retryFromHeaderRaw)
      : undefined;

    return {
      status,
      message,
      retryAfterSeconds:
        Number.isFinite(retryFromDetail)
          ? retryFromDetail
          : Number.isFinite(retryFromHeader)
            ? retryFromHeader
            : undefined,
    };
  }

  return {
    status: 0,
    message: error instanceof Error ? error.message : "Request failed",
  };
};

// Gemini API endpoints
export const geminiApi = {
  generateText: (prompt: string) =>
    apiClient.post("/gemini/generate-text", { prompt }),

  analyzeStory: (payload: AnalyzeStoryPayload) =>
    apiClient.post("/gemini/analyze-story", payload),

  analyzeStoryStructured: (payload: AnalyzeStoryPayload) =>
    apiClient.post<AnalyzeStoryStructuredResponse>("/gemini/analyze-story-structured", payload),

  generateCharacterPrompt: (characterDescription: string) =>
    apiClient.post("/gemini/character-prompt", {
      character_description: characterDescription,
    }),

  generatePanelScript: (sceneDescription: string) =>
    apiClient.post("/gemini/panel-script", {
      scene_description: sceneDescription,
    }),

  health: () => apiClient.get("/gemini/health"),
};

// Comic Generation Pipeline endpoints
export const comicApi = {
  generateComic: (payload: {
    story_text: string;
    main_characters: number;
    num_chapters: number;
    target_pages: number;
    genre_tone: string;
    art_style: string;
    max_panels_per_page: number;
    generate_markdown?: boolean;
  }) => apiClient.post("/comics/generate", payload),

  getStatus: (jobId: string) => apiClient.get(`/comics/status/${jobId}`),

  getResults: (jobId: string) => apiClient.get(`/comics/results/${jobId}`),

  listJobs: () => apiClient.get("/comics/jobs"),
};

export default apiClient;

